{
  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using terms from the lesson content about security architecture components. Refer to the flashcards for clues.",
        "codeTemplate": "The primary function of __________ is to protect the network boundary from external threats, while __________ divides the network into segments to limit access.",
        "options": [
          "Perimeter Security",
          "Network Segmentation",
          "Threat Actors",
          "Threat Modeling"
        ],
        "correctAnswer": "Perimeter Security,Network Segmentation",
        "explanation": "Perimeter Security acts as the first line of defense against unauthorized access, while Network Segmentation helps reduce vulnerabilities by limiting access."
      },
      {
        "instruction": "Identify the correct terms to complete the sentences based on the concepts learned in this module.",
        "codeTemplate": "Understanding __________ is crucial for identifying potential risks, and recognizing __________ helps in determining who may exploit these vulnerabilities.",
        "options": [
          "Threat Modeling",
          "Perimeter Security",
          "Threat Actors",
          "Network Segmentation"
        ],
        "correctAnswer": "Threat Modeling,Threat Actors",
        "explanation": "Threat Modeling is essential for identifying risks, and Threat Actors are individuals or groups that may exploit vulnerabilities."
      }
    ]
  }
}
